,\"layout\":{\"type\":\"constrained\"}} -->\r\n<div class=\"wp-block-group\" style=\"background-color:#FFFFFF;padding-top:clamp(4rem,8vw,7rem);padding-bottom:clamp(4rem,8vw,7rem)\">\r\n<!-- wp:columns {\"style\":{\"spacing\":{\"blockGap\":{\"left\":\"4rem\"}}}} -->\r\n<div class=\"wp-block-columns\">\r\n<!-- wp:column {\"width\":\"55%\"} -->\r\n<div class=\"wp-block-column\" style=\"flex-basis:55%\">\r\n<!-- wp:heading {\"level\":6,\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.75rem\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.15em\"},\"spacing\":{\"margin\":{\"bottom\":\"0.75rem\"}}}} -->\r\n<h6 class=\"wp-block-heading\" style=\"color:#3B82F6;font-size:0.75rem;font-weight:700;letter-spacing:0.15em;text-transform:uppercase;margin-bottom:0.75rem\">What Is It</h6>\r\n<!-- /wp:heading -->\r\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"clamp(2rem,4vw,3.5rem)\",\"fontWeight\":\"800\",\"lineHeight\":\"1.05\"}}} -->\r\n<h2 class=\"wp-block-heading\" style=\"color:#0F172A;font-size:clamp(2rem,4vw,3.5rem);font-weight:800;line-height:1.05\">1-ON-1 PERSONAL TRAINING<br><span style=\"color:#3B82F6\">AT EP FITNESS</span></h2>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"1.05rem\"},\"spacing\":{\"margin\":{\"top\":\"1.5rem\"}}}} -->\r\n<p style=\"color:#374151;font-size:1.05rem;margin-top:1.5rem\">The gold standard in fitness coaching. You get a dedicated coach, undivided attention, and a program built entirely around you — your goals, your schedule, your body. No generic templates, no guesswork.</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:heading {\"level\":4,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.25rem\",\"fontWeight\":\"700\"},\"spacing\":{\"margin\":{\"top\":\"2rem\",\"bottom\":\"0.75rem\"}}}} -->\r\n<h4 class=\"wp-block-heading\" style=\"colo