ock-columns are-vertically-aligned-center\">\r\n<!-- wp:column {\"width\":\"55%\"} -->\r\n<div class=\"wp-block-column\" style=\"flex-basis:55%\">\r\n<!-- wp:heading {\"level\":6,\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.75rem\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.15em\"}}} -->\r\n<h6 class=\"wp-block-heading\" style=\"color:#3B82F6;font-size:0.75rem;font-weight:700;letter-spacing:0.15em;text-transform:uppercase\">Who We Are</h6>\r\n<!-- /wp:heading -->\r\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"clamp(2rem,4vw,3.5rem)\",\"fontWeight\":\"800\",\"lineHeight\":\"1.05\"}}} -->\r\n<h2 class=\"wp-block-heading\" style=\"color:#0F172A;font-size:clamp(2rem,4vw,3.5rem);font-weight:800;line-height:1.05\">MORE THAN<br><span style=\"color:#3B82F6\">JUST A GYM.</span></h2>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"1.05rem\"}}} -->\r\n<p style=\"color:#374151;font-size:1.05rem\">EP Fitness Personal Training is Wichita\'s premier personal training company, serving the metro area across 4 locations. We specialize in 1-on-1 and semi-private personal training for adults who want real, lasting results.</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"1.05rem\"}}} -->\r\n<p style=\"color:#374151;font-size:1.05rem\">Our coaches are passionate, certified, and dedicated to your success. Every member gets a fully customized program built around their goals, schedule, and fitness level — with consistent coaching every step of the way.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {\"width\":\"45%\"} -->\r\n<div class=\"wp-block-column\" style=\"flex-basis:45%\">\r\n<!-- wp:image {\"id\":36,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\r\n<figure class=\"wp-block-image size-large\"><img src=\"http://ep-fitness.local/wp-content/uploads/2026/04/2025-06-11-7-1.webp\" alt=\"EP Fitness coaching session\" class=\"wp-image-36\"/></figure>\r\n<!-- /wp:image -->\r\n</div>\r\n<!-- /wp:column -->\r\n</div>\r\n<!-- /wp:columns -->\r\n</div>\r\n<!-- /wp:group -->\r\n\r\n<!-- wp:group {\"style\":{\"color\":{\"background\":\"#F3F4F6\"},\"spacing\":{\"padding\":{\"top\":\"clamp(4rem,8vw,7rem)\",\"bottom\":\"clamp(4rem,8vw,7rem)\"}}},\"layout\":{\"type\":\"constrained\"}} -->\r\n<div class=\"wp-block-group\" style=\"background-color:#F3F4F6;padding-top:clamp(4rem,8vw,7rem);padding-bottom:clamp(4rem,8vw,7rem)\">\r\n<!-- wp:heading {\"level\":6,\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.75rem\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.15em\"}}} -->\r\n<h6 class=\"wp-block-heading\" style=\"color:#3B82F6;font-size:0.75rem;font-weight:700;letter-spacing:0.15em;text-transform:uppercase\">Meet The Team</h6>\r\n<!-- /wp:heading -->\r\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"clamp(2rem,4vw,3.5rem)\",\"fontWeight\":\"800\"}}} -->\r\n<h2 class=\"wp-block-heading\" style=\"color:#0F172A;font-size:clamp(2rem,4vw,3.5rem);font-weight:800\">YOUR COACHES.<br><span style=\"color:#3B82F6\">YOUR CHAMPIONS.</span></h2>\r\n<!-- /wp:heading -->\r\n<!-- wp:columns {\"isStackedOnMobile\":true} -->\r\n<div class=\"wp-block-columns\">\r\n<!-- wp:column {\"className\":\"ep-team-card\"} -->\r\n<div class=\"wp-block-column ep-team-card\">\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.5rem\",\"fontWeight\":\"800\"}}} -->\r\n<h3 class=\"wp-block-heading\" style=\"color:#0F172A;font-size:1.5rem;font-weight:800\">COACH CODY WEBER</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.8rem\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.1em\"}}} -->\r\n<p class=\"ep-team-role\" style=\"color:#3B82F6;font-size:0.8rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase\">Founder &amp; Head Coach</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p style=\"color:#374151;font-size:0.95rem\">Certified personal trainer with 10+ years experience. Specializes in strength, fat loss, and performance training for adults 40+.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {\"className\":\"ep-team-card\"} -->\r\n<div class=\"wp-block-column ep-team-card\">\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.5rem\",\"fontWeight\":\"800\"}}} -->\r\n<h3 class=\"wp-block-heading\" style=\"color:#0F172A;font-size:1.5rem;font-weight:800\">COACH LILLIAN</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.8rem\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.1em\"}}} -->\r\n<p class=\"ep-team-role\" style=\"color:#3B82F6;font-size:0.8rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase\">Performance Coach</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p style=\"color:#374151;font-size:0.95rem\">Specializes in functional movement, injury prevention, and building long-term sustainable fitness habits for busy professionals.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {\"className\":\"ep-team-card\"} -->\r\n<div class=\"wp-block-column ep-team-card\">\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.5rem\",\"fontWeight\":\"800\"}}} -->\r\n<h3 class=\"