\r\n<p  class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Certified personal trainer with 10+ years experience. Specializes in strength, fat loss, and performance training for adults 40+.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {\"className\":\"ep-team-card\"} -->\r\n<div class=\"wp-block-column ep-team-card\">\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.5rem\",\"fontWeight\":\"800\"}}} -->\r\n<h3  class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.5rem;font-weight:800\">COACH LILLIAN</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.8rem\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.1em\"}}} -->\r\n<p  class=\"ep-team-role has-text-color\" style=\"color:#3B82F6;font-size:0.8rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase\">Performance Coach</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p  class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Specializes in functional movement, injury prevention, and building long-term sustainable fitness habits for busy professionals.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {\"className\":\"ep-team-card\"} -->\r\n<div class=\"wp-block-column ep-team-card\">\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.5rem\",\"fontWeight\":\"800\"}}} -->\r\n<h3  class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.5rem;font-weight:800\">COACH THOMAS</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.8rem\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.1em\"}}} -->\r\n<p  class=\"ep-team-role has-text-color\" style=\"color:#3B82F6;font-size:0.8rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase\">Strength &amp; Conditioning</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p  class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Expert in strength and conditioning, sports performance, and helping clients break through plateaus with science-backed programming.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:column -->\r\n</div>\r\n<!-- /wp:columns -->\r\n</div>\r\n<!-- /wp:group -->\r\n\r\n<!-- wp:cover {\"url\":\"http://ep-fitness.local/wp-content/uploads/2026/04/2024-07-23-3.webp\",\"id\":38,\"dimRatio\":75,\"style\":{\"spacing\":{\"padding\":{\"top\":\"clamp(4rem, 8vw, 6rem)\",\"bottom\":\"clamp(4rem, 8vw, 6rem)\"}}},\"layout\":{\"type\":\"constrained\"}} -->\r\n<div class=\"wp-block-cover\" style=\"padding-top:clamp(4rem, 8vw, 6rem);padding-bottom:clamp(4rem, 8vw, 6rem)\"><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim-75 has-background-dim\" style=\"background-color:#0F172A\"></span><img class=\"wp-block-cover__image-background wp-image-38\" alt=\"EP Fitness\" src=\"http://ep-fitness.local/wp-content/uploads/2026/04/2024-07-23-3.webp\" data-object-fit=\"cover\"/><div class=\"wp-block-cover__inner-container\">\r\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":6,\"style\":{\"color\":{\"text\":\"#60A5FA\"},\"typography\":{\"fontSize\":\"0.75rem\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.15em\"}}} -->\r\n<h6  class=\"wp-block-heading has-text-align-center has-text-color\" style=\"color:#60A5FA;font-size:0.75rem;font-weight:700;letter-spacing:0.15em;text-transform:uppercase\">Start Today</h6>\r\n<!-- /wp:heading -->\r\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":2,\"style\":{\"color\":{\"