nation\":\"none\"} -->\r\n<figure class=\"wp-block-image size-large\"><img src=\"http://ep-fitness.local/wp-content/uploads/2026/04/2025-06-11-7-1.webp\" alt=\"EP Fitness coaching session\" class=\"wp-image-36\"/></figure>\r\n<!-- /wp:image -->\r\n</div>\r\n<!-- /wp:column -->\r\n</div>\r\n<!-- /wp:columns -->\r\n</div>\r\n<!-- /wp:group -->\r\n\r\n<!-- wp:group {\"style\":{\"color\":{\"background\":\"#F3F4F6\"},\"spacing\":{\"padding\":{\"top\":\"clamp(4rem, 8vw, 7rem)\",\"bottom\":\"clamp(4rem, 8vw, 7rem)\"}}},\"layout\":{\"type\":\"constrained\"}} -->\r\n<div  class=\"wp-block-group has-background is-layout-constrained wp-block-group-is-layout-constrained\" style=\"background-color:#F3F4F6;padding-top:clamp(4rem, 8vw, 7rem);padding-bottom:clamp(4rem, 8vw, 7rem)\">\r\n<!-- wp:heading {\"level\":6,\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.75rem\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.15em\"}}} -->\r\n<h6  class=\"wp-block-heading has-text-color\" style=\"color:#3B82F6;font-size:0.75rem;font-weight:700;letter-spacing:0.15em;text-transform:uppercase\">Meet The Team</h6>\r\n<!-- /wp:heading -->\r\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"clamp(2rem, 4vw, 3.5rem)\",\"fontWeight\":\"800\"}}} -->\r\n<h2  class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:clamp(2rem, 4vw, 3.5rem);font-weight:800\">YOUR COACHES.<br><span style=\"color:#3B82F6\">YOUR CHAMPIONS.</span></h2>\r\n<!-- /wp:heading -->\r\n<!-- wp:columns {\"isStackedOnMobile\":true} -->\r\n<div class=\"wp-block-columns is-layout-flex wp-block-columns-is-layout-flex\">\r\n<!-- wp:column {\"className\":\"ep-team-card\"} -->\r\n<div class=\"wp-block-column ep-team-card is-layout-flow wp-block-column-is-layout-flow\">\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.5rem\",\"fontWeight\":\"800\"}}} --