ass=\"wp-block-columns is-layout-flex wp-block-columns-is-layout-flex\">\r\n<!-- wp:column {\"width\":\"55%\"} -->\r\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:55%\">\r\n<!-- wp:heading {\"level\":6,\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.75rem\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.15em\"}}} -->\r\n<h6  class=\"wp-block-heading has-text-color\" style=\"color:#3B82F6;font-size:0.75rem;font-weight:700;letter-spacing:0.15em;text-transform:uppercase\">What Is It</h6>\r\n<!-- /wp:heading -->\r\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"clamp(2rem, 4vw, 3.5rem)\",\"fontWeight\":\"800\",\"lineHeight\":\"1.05\"}}} -->\r\n<h2  class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:clamp(2rem, 4vw, 3.5rem);font-weight:800;line-height:1.05\">1-ON-1 PERSONAL TRAINING<br><span style=\"color:#3B82F6\">AT EP FITNESS</span></h2>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"1.05rem\"}}} -->\r\n<p  class=\"has-text-color\" style=\"color:#374151;font-size:1.05rem\">The gold standard in fitness coaching. You get a dedicated coach, undivided attention, and a program built entirely around you — your goals, your schedule, your body. No generic templates, no guesswork.</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:heading {\"level\":4,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.25rem\",\"fontWeight\":\"700\"}}} -->\r\n<h4  class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.25rem;font-weight:700\">WHO IS IT FOR?</h4>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"1rem\"}}} -->\r\n<p  class=\"has-text-color\" style=\"color:#374151;font-size:1rem\">Adults 40+ looking for real, lasting results. Beginners who want expert guidance from day one. Experienced athletes hitting a plateau. Anyone who wants a dedicated coach in their corner.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {\"width\":\"45%\"} -->\r\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:45%\">\r\n<!-- wp:heading {\"level\":4,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.25rem\",\"fontWeight\":\"700\"}}} -->\r\n<h4  class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.25rem;font-weight:700\">WHAT\'S INCLUDED</h4>\r\n<!-- /wp:heading -->\r\n<!-- wp:list {\"style\":{\"spacing\":{\"padding\":{\"left\":\"0\"}}},\"className\":\"ep-checklist\"} -->\r\n<ul class=\"ep-checklist\" style=\"padding-left:0\">\r\n<!-- wp:list-item -->\r\n<li>Comprehensive body composition assessment</li>\r\n<!-- /wp:list-item -->\r\n<!-- wp:list-item -->\r\n<li>100% customized training program</li>\r\n<!-- /wp:list-item -->\r\n<!-- wp:list-item -->\r\n<li>Weekly check-ins with your coach</li>\r\n<!-- /wp:list-item -->\r\n<!-- wp:list-item -->\r\n<li>Nutrition guidance and meal planning support</li>\r\n<!-- /wp:list-item -->\r\n<!-- wp:list-item -->\r\n<li>Progress tracking and program adjustments</li>\r\n<!-- /wp:list-item -->\r\n<!-- wp:list-item -->\r\n<li>Flexible scheduling — morning, evening, weekends</li>\r\n<!-- /wp:list-item -->\r\n<!-- wp:list-item -->\r\n<li>No contracts required</li>\r\n<!-- /wp:list-item -->\r\n</ul>\r\n<!-- /wp:list -->\r\n<!-- wp:buttons {} -->\r\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\" style=\"margin-top:2rem\">\r\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#3B82F6\",\"text\":\"#FFFFFF\"},\"border\":{\"radius\":\"0px\"},\"typography\":{\"fontFamily\":\"var:preset|font-family|barlow-condensed\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.1em\",\"fontSize\":\"1.1rem