":{\"padding\":{\"left\":\"0\"}}},\"className\":\"ep-checklist\"} -->\r\n<ul class=\"ep-checklist\" style=\"padding-left:0\">\r\n<!-- wp:list-item -->\r\n<li>Comprehensive body composition assessment</li>\r\n<!-- /wp:list-item -->\r\n<!-- wp:list-item -->\r\n<li>100% customized training program</li>\r\n<!-- /wp:list-item -->\r\n<!-- wp:list-item -->\r\n<li>Weekly check-ins with your coach</li>\r\n<!-- /wp:list-item -->\r\n<!-- wp:list-item -->\r\n<li>Nutrition guidance and meal planning support</li>\r\n<!-- /wp:list-item -->\r\n<!-- wp:list-item -->\r\n<li>Progress tracking and program adjustments</li>\r\n<!-- /wp:list-item -->\r\n<!-- wp:list-item -->\r\n<li>Flexible scheduling — morning, evening, weekends</li>\r\n<!-- /wp:list-item -->\r\n<!-- wp:list-item -->\r\n<li>No contracts required</li>\r\n<!-- /wp:list-item -->\r\n</ul>\r\n<!-- /wp:list -->\r\n<!-- wp:buttons {} -->\r\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\" style=\"\">\r\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#3B82F6\",\"text\":\"#FFFFFF\"},\"border\":{\"radius\":\"0px\"},\"typography\":{\"fontFamily\":\"var:preset|font-family|barlow-condensed\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.1em\",\"fontSize\":\"1.1rem\"},\"spacing\":{\"padding\":{\"top\":\"1.1rem\",\"bottom\":\"1.1rem\",\"left\":\"2.5rem\",\"right\":\"2.5rem\"}}}} -->\r\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/contact\" style=\"background-color:#3B82F6;color:#FFFFFF;border-radius:0px;padding-top:1.1rem;padding-right:2.5rem;padding-bottom:1.1rem;padding-left:2.5rem;font-family:var(--wp--preset--font-family--barlow-condensed);font-size:1.1rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase\">Start Training Today</a></div>\r\n<!-- /wp:button -->\r\n</div>\r\n<!-- /wp:buttons -->\r\n</div>\r\n<!-- /wp:column -->\r\n</div>\r\n<!-- /wp:columns -->\r\n</div>\r\n<!-- /wp:group -->\r\n<!-- wp:cove