TRAINING</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Undivided coach attention. Fully customized workouts. Maximum results. Your schedule, your goals, your program.</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:buttons -->\r\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\r\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#3B82F6\",\"text\":\"#FFFFFF\"},\"border\":{\"radius\":\"0px\"},\"typography\":{\"fontFamily\":\"var:preset|font-family|barlow-condensed\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.08em\",\"fontSize\":\"0.95rem\"},\"spacing\":{\"padding\":{\"top\":\"0.7rem\",\"bottom\":\"0.7rem\",\"left\":\"1.5rem\",\"right\":\"1.5rem\"}}}} -->\r\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/personal-training\" style=\"background-color:#3B82F6;color:#FFFFFF;border-radius:0px;padding-top:0.7rem;padding-right:1.5rem;padding-bottom:0.7rem;padding-left:1.5rem;font-family:var(--wp--preset--font-family--barlow-condensed);font-size:0.95rem;font-weight:700;letter-spacing:0.08em;text-transform:uppercase\">Learn More →</a></div>\r\n<!-- /wp:button -->\r\n</div>\r\n<!-- /wp:buttons -->\r\n</div>\r\n<!-- /wp:column -->\r\n\r\n<!-- wp:column {\"className\":\"ep-service-card\"} -->\r\n<div class=\"wp-block-column ep-service-card is-layout-flow wp-block-column-is-layout-flow\">\r\n<!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"2rem\"}}} -->\r\n<p style=\"font-size:2rem\">👥</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.9rem\",\"fontWeight\":\"800\"}}} -->\r\n<h3 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.9rem;font-weight:800\">SEMI-PRIVATE</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Max 6 per session. Community energy with personalized coaching. The best of both worlds at a competitive price.</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:buttons -->\r\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\r\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#3B82F6\",\"text\":\"#FFFFFF\"},\"border\":{\"radius\":\"0px\"},\"typography\":{\"fontFamily\":\"var:preset|font-family|barlow-condensed\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.08em\",\"fontSize\":\"0.95rem\"},\"spacing\":{\"padding\":{\"top\":\"0.7rem\",\"bottom\":\"0.7rem\",\"left\":\"1.5rem\",\"right\":\"1.5rem\"}}}} -->\r\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/semi-private-training\" style=\"background-color:#3B82F6;color:#FFFFFF;border-radius:0px;padding-top:0.7rem;padding-right:1.5rem;padding-bottom:0.7rem;padding-left:1.5rem;font-family:var(--wp--preset--font-family--barlow-condensed);font-size:0.95rem;font-weight:700;letter-spacing:0.08em;text-transform:uppercase\">Learn More →</a></div>\r\n<!-- /wp:button -->\r\n</div>\r\n<!-- /wp:buttons -->\r\n</div>\r\n<!-- /wp:column -->\r\n\r\n<!-- wp:column {\"className\":\"ep-service-card\"} -->\r\n<div class=\"wp-block-column ep-service-card is-layout-flow wp-block-column-is-layout-flow\">\r\n<!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"2rem\"}}} -->\r\n<p style=\"font-size:2rem\">💻</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.9rem\",\"fontWeight\":\"800\"}}} -->\r\n<h3 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.9rem;font-weight:800\">ONLINE TRAINING</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:pa