font-size:0.95rem\">Certified personal trainer with 10+ years experience. Specializes in strength, fat loss, and performance training for adults 35+.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {\"className\":\"ep-team-card\"} -->\r\n<div class=\"wp-block-column ep-team-card is-layout-flow wp-block-column-is-layout-flow\">\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.5rem\",\"fontWeight\":\"800\"}}} -->\r\n<h3 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.5rem;font-weight:800\">COACH LILLIAN</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.8rem\",\"fontWeight\":\"700\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.1em\"}}} -->\r\n<p class=\"ep-team-role has-text-color\" style=\"color:#3B82F6;font-size:0.8rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase\">Performance Coach</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Specializes in functional movement, injury prevention, and building long-term sustainable fitness habits for busy professionals.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {\"className\":\"ep-team-card\"} -->\r\n<div class=\"wp-block-column ep-team-card is-layout-flow wp-block-column-is-layout-flow\">\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.5rem\",\"fontWeight\":\"800\"}}} -->\r\n<h3 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.5rem;font-weight:800\">COACH THOMAS</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.8rem\",\"fontWeight\":\"700\",\