hy\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Max 6 per session. Community energy with personalized coaching. The best of both worlds at a competitive price.</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"flex-start\"},\"style\":{\"spacing\":{\"blockGap\":\"1rem\"}}} -->\r\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\" style=\"gap:1rem\">\r\n<!-- wp:button {\"backgroundColor\":false,\"textColor\":false} -->\r\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/semi-private-training\" style=\"background-color:#0F172A;color:#FFFFFF;\">Learn More →</a></div>\r\n<!-- /wp:button -->\r\n</div>\r\n<!-- /wp:buttons -->\r\n</div>\r\n<!-- /wp:group -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {} -->\r\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\r\n<!-- wp:group {\"className\":\"ep-service-card\",\"layout\":{\"type\":\"constrained\"}} -->\r\n<div class=\"wp-block-group ep-service-card is-layout-constrained wp-block-group-is-layout-constrained\">\r\n<!-- wp:paragraph {\"className\":\"ep-service-number\"} -->\r\n<p class=\"ep-service-number\">03</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.4rem\",\"fontWeight\":\"800\",\"letterSpacing\":\"0.05em\"}}} -->\r\n<h3 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.4rem;font-weight:800;letter-spacing:0.05em\">ONLINE TRAINING</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Train anywhere, anytime. Expert coaching delivered digitally. Perfect for busy schedules and remote clients.</p>\r\n<!-- /wp:paragraph -->\r\n<!-- w