FF;font-size:clamp(2.2rem,4vw,3.5rem);font-weight:800\">READY TO<br><span style=\"color:#60A5FA\">CHANGE YOUR LIFE?</span></h2>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.8)\"},\"typography\":{\"fontSize\":\"1rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:rgba(255,255,255,0.8);font-size:1rem\">Call us at <a href=\"tel:3163159190\" style=\"color:#60A5FA;font-weight:600\">(316) 315-9190</a> or fill out our contact form. We\'ll build a custom program around your goals, schedule, and fitness level.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {\"width\": \"40%\"} -->\r\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:40%\">\r\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"flex-start\"},\"style\":{\"spacing\":{\"blockGap\":\"1rem\"}}} -->\r\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\" style=\"gap:1rem\">\r\n<!-- wp:button {\"backgroundColor\":false,\"textColor\":false,\"width\":\"100%\"} -->\r\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/contact\" style=\"background-color:#3B82F6;color:#FFFFFF;width:100%;\">Get Your Free Consultation</a></div>\r\n<!-- /wp:button -->\r\n<!-- wp:button {\"className\":\"is-style-outline\",\"width\":\"100%\"} -->\r\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link wp-element-button\" href=\"tel:3163159190\" style=\"color:#FFFFFF;border-color:#FFFFFF;width:100%;\">(316) 315-9190</a></div>\r\n<!-- /wp:button -->\r\n</div>\r\n<!-- /wp:buttons -->\r\n</div>\r\n<!-- /wp:column -->\r\n</div>\r\n<!-- /wp:columns -->\r\n</div>\r\n</div>\r\n<!-- /wp:cover -->\r\n','Home','','inherit','closed','closed','','5-revision-v1','','','2026-04-03 11:52:59','2026-04-03 11:52:59','',5,'http://ep-fitness.local/?p=117',0,'revision','',0),(118,0,'2026-04-03 11:52:59','2026-04-03 11: