Size\":\"0.95rem\"}}} -->\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Undivided coach attention. Fully customized workouts. Maximum results. Your schedule, your goals, your program.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"className\":\"is-layout-flex wp-block-buttons-is-layout-flex\",\"style\":{\"spacing\":{\"blockGap\":\"1rem\"}},\"layout\":{\"type\":\"flex\",\"justifyContent\":\"flex-start\"}} -->\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/personal-training\">Learn More →</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"className\":\"is-layout-flow wp-block-column-is-layout-flow\"} -->\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\"><!-- wp:group {\"className\":\"ep-service-card is-layout-constrained wp-block-group-is-layout-constrained\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group ep-service-card is-layout-constrained wp-block-group-is-layout-constrained\"><!-- wp:paragraph {\"className\":\"ep-service-number\"} -->\n<p class=\"ep-service-number\">02</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.4rem\",\"fontWeight\":\"800\",\"letterSpacing\":\"0.05em\"}}} -->\n<h3 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.4rem;font-weight:800;letter-spacing:0.05em\">SEMI-PRIVATE</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Max 6 per session. Community energy with personalized coaching. The best of both worlds at a competitive price.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"className\":\"is-layout-flex wp-block-buttons-is-layout-flex\",\"style\":{\"spacing\":{\"blockGap\":\"1rem\"}},\"layout\":{\"type\":\"flex\",\"justifyContent\":\"flex-start\"}} -->\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/semi-private-training\">Learn More →</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"className\":\"is-layout-flow wp-block-column-is-layout-flow\"} -->\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\"><!-- wp:group {\"className\":\"ep-service-card is-layout-constrained wp-block-group-is-layout-constrained\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group ep-service-card is-layout-constrained wp-block-group-is-layout-constrained\"><!-- wp:paragraph {\"className\":\"ep-service-number\"} -->\n<p class=\"ep-service-number\">03</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.4rem\",\"fontWeight\":\"800\",\"letterSpacing\":\"0.05em\"}}} -->\n<h3 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.4rem;font-weight:800;letter-spacing:0.05em\">ONLINE TRAINING</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Train anywhere, anytime. Expert coaching delivered digitally. Perfect for busy schedules and remote clients.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"className\":\"is-layout-flex wp-block-buttons-is-layout-flex\",\"style\":{\"spacing\":{\"blockGap\":\"1rem\"}},\"layout\":{\"type\":\"flex\",\"justifyContent\":\"flex-start\"}} -->\n<div class=\"wp-block-buttons is-layout-flex wp-blo