vw,3.2rem);font-weight:800\">THE EP FITNESS<br><span style=\"color:#3B82F6\">DIFFERENCE.</span></h2>\r\n<!-- /wp:heading -->\r\n<!-- wp:columns {\"className\": \"ep-pillars-cols\"} -->\r\n<div class=\"wp-block-columns is-layout-flex wp-block-columns-is-layout-flex ep-pillars-cols\">\r\n<!-- wp:column {} -->\r\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\r\n<!-- wp:group {\"className\":\"ep-pillar-card\",\"layout\":{\"type\":\"constrained\"}} -->\r\n<div class=\"wp-block-group ep-pillar-card is-layout-constrained wp-block-group-is-layout-constrained\">\r\n<!-- wp:paragraph {\"className\":\"ep-pillar-number\"} -->\r\n<p class=\"ep-pillar-number\">01</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:heading {\"level\":4,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.2rem\",\"fontWeight\":\"800\"}}} -->\r\n<h4 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.2rem;font-weight:800\">REAL COACHES</h4>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Every EP coach is a certified professional who has studied your program before your first session. No rotation, no substitutes.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:group -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {} -->\r\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\r\n<!-- wp:group {\"className\":\"ep-pillar-card\",\"layout\":{\"type\":\"constrained\"}} -->\r\n<div class=\"wp-block-group ep-pillar-card is-layout-constrained wp-block-group-is-layout-constrained\">\r\n<!-- wp:paragraph {\"className\":\"ep-pillar-number\"} -->\r\n<p class=\"ep-pillar-number\">02</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:heading {\"level\":4,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.2rem\",\"fontWeight\":\"800\"}}} -->\r\n<h4 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.2rem;font-weight:800\">REAL PLANS</h4>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">No templates. Every program is built from scratch around your body composition, goals, and weekly availability.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:group -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {} -->\r\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\r\n<!-- wp:group {\"className\":\"ep-pillar-card\",\"layout\":{\"type\":\"constrained\"}} -->\r\n<div class=\"wp-block-group ep-pillar-card is-layout-constrained wp-block-group-is-layout-constrained\">\r\n<!-- wp:paragraph {\"className\":\"ep-pillar-number\"} -->\r\n<p class=\"ep-pillar-number\">03</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:heading {\"level\":4,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.2rem\",\"fontWeight\":\"800\"}}} -->\r\n<h4 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.2rem;font-weight:800\">REAL RESULTS</h4>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">We measure everything — body comp, strength benchmarks, habits. Because accountability without data is just hope.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:group -->\r\n</div>\r\n<!-- /wp:column -->\r\n</div>\r\n<!-- /wp:columns -->\r\n</div>\r\n<!-- /wp:group -->\r\n<!-- wp:group {\"style\": {\"color\": {\"background\": \"#FFFFFF\"}, \"spacing\": {\"padding\": {\"top\": \"clamp(5rem, 10vw, 8rem)\", \"bottom\": \"clamp(5rem, 10vw, 8rem)\", \"left\": \"2rem\", \"right\": \"2rem\"}}}, \"layout\": {\"type\": \"constrained\"}} -->\r\n<div class=\"wp-block-group is-layout-constrained wp-block-group-is-layout-constrained has-background\" style=\"background-color:#FFFFFF;padding-top:clamp(5rem, 10vw, 8rem);padding-bottom:clamp(5rem, 10vw, 8rem)\">\r\n<!-- wp:heading {\"level\":6,\"className\":\"ep-eyebrow\",\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.75rem\",\"fontWeight\":\"700\",\"letterSpacing\":\"0.12em\",\"textTransform\":\"uppercase\"}}} -->\r\n<h6 class=\"wp-block-heading ep-eyebrow has-text-color\" style=\"color:#3B82F6;font-size:0.75rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase\">Meet The Team</h6>\r\n<!-- /wp:heading -->\r\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"clamp(2.2rem,4vw,3.2rem)\",\"fontWeight\":\"800\"}}} -->\r\n<h2 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:clamp(2.2rem,4vw,3.2rem);font-weight:800\">YOUR COACHES.<br><span style=\"color:#3B82F6\">YOUR CHAMPIONS.</span></h2>\r\n<!-- /wp:heading -->\r\n<!-- wp:columns {\"className\": \"ep-team-cols\"} -->\r\n<div class=\"wp-block-columns is-layout-flex wp-block-columns-is-layout-flex ep-team-cols\">\r\n<!-- wp:column {} -->\r\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\r\n<!-- wp:group {\"className\":\"ep-team-card\",\"layout\":{\"type\":\"constrained\"}} -->\r\n<div class=\"wp-block-group ep-team-card is-layout-constrained wp-block-group-is-layout-constrained\">\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.2rem\",\"fontWeight\":\"800\"}}} -->\r\n<h3 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.2rem;font-weight:800\">COACH CODY WEBER</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"className\":\"ep-team-role\",\"style\":{\"color\":{\"text\":\"#6B7280\"},\"typography\":{\"fontSize\":\"0.85rem\"}}} -->\r\n<p class=\"ep-team-role has-text-color\" style=\"color:#6B7280;font-size:0.85rem\">Founder & Head Coach</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.8rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#3B82F6;font-size:0.8rem\">NASM-CPT · Precision Nutrition L1 · 10+ yrs</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Wichita\'s most sought-after personal trainer. Coach Cody built EP Fitness around one belief: every person deserves a real coach, a real plan, and real results — not a generic template.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:group -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {} -->\r\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\r\n<!-- wp:group {\"className\":\"ep-team-card\",\"layout\":{\"type\":\"constrained\"}} -->\r\n<div class=\"wp-block-group ep-team-card is-layout-constrained wp-block-group-is-layout-constrained\">\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.2rem\",\"fontWeight\":\"800\"}}} -->\r\n<h3 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.2rem;font-weight:800\">COACH LILLIAN</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"className\":\"ep-team-role\",\"style\":{\"color\":{\"text\":\"#6B7280\"},\"typography\":{\"fontSize\":\"0.85rem\"}}} -->\r\n<p class=\"ep-team-role has-text-color\" style=\"color:#6B7280;font-size:0.85rem\">Performance Coach</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.8rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#3B82F6;font-size:0.8rem\">FMS Certified · Corrective Exercise Specialist</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Specializes in functional movement, injury prevention, and building long-term sustainable fitness habits for busy professionals.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:group -->\r\n</div>\r\n<!-- /wp:column -->\r\n<!-- wp:column {} -->\r\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\r\n<!-- wp:group {\"className\":\"ep-team-card\",\"layout\":{\"type\":\"constrained\"}} -->\r\n<div class=\"wp-block-group ep-team-card is-layout-constrained wp-block-group-is-layout-constrained\">\r\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"1.2rem\",\"fontWeight\":\"800\"}}} -->\r\n<h3 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:1.2rem;font-weight:800\">COACH THOMAS</h3>\r\n<!-- /wp:heading -->\r\n<!-- wp:paragraph {\"className\":\"ep-team-role\",\"style\":{\"color\":{\"text\":\"#6B7280\"},\"typography\":{\"fontSize\":\"0.85rem\"}}} -->\r\n<p class=\"ep-team-role has-text-color\" style=\"color:#6B7280;font-size:0.85rem\">Strength & Conditioning</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.8rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#3B82F6;font-size:0.8rem\">CSCS · Sports Performance Specialist</p>\r\n<!-- /wp:paragraph -->\r\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#374151\"},\"typography\":{\"fontSize\":\"0.95rem\"}}} -->\r\n<p class=\"has-text-color\" style=\"color:#374151;font-size:0.95rem\">Expert in strength and conditioning, sports performance, and helping clients break through plateaus with science-backed programming.</p>\r\n<!-- /wp:paragraph -->\r\n</div>\r\n<!-- /wp:group -->\r\n</div>\r\n<!-- /wp:column -->\r\n</div>\r\n<!-- /wp:columns -->\r\n</div>\r\n<!-- /wp:group -->\r\n<!-- wp:co