r\" style=\"color:rgba(255,255,255,0.7);font-size:0.85rem;letter-spacing:0.1em;text-transform:uppercase\">Age Group Served</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"is-layout-constrained wp-block-group-is-layout-constrained\",\"style\":{\"color\":{\"background\":\"#F3F4F6\"},\"spacing\":{\"padding\":{\"top\":\"clamp(5rem, 10vw, 8rem)\",\"bottom\":\"clamp(5rem, 10vw, 8rem)\",\"left\":\"2rem\",\"right\":\"2rem\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group is-layout-constrained wp-block-group-is-layout-constrained has-background\" style=\"background-color:#F3F4F6;padding-top:clamp(5rem, 10vw, 8rem);padding-right:2rem;padding-bottom:clamp(5rem, 10vw, 8rem);padding-left:2rem\"><!-- wp:heading {\"level\":6,\"className\":\"ep-eyebrow\",\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.75rem\",\"fontWeight\":\"700\",\"letterSpacing\":\"0.12em\",\"textTransform\":\"uppercase\"}}} -->\n<h6 class=\"wp-block-heading ep-eyebrow has-text-color\" style=\"color:#3B82F6;font-size:0.75rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase\">How We Train</h6>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"style\":{\"color\":{\"text\":\"#0F172A\"},\"typography\":{\"fontSize\":\"clamp(2.5rem,5vw,4rem)\",\"fontWeight\":\"800\"}}} -->\n<h2 class=\"wp-block-heading has-text-color\" style=\"color:#0F172A;font-size:clamp(2.5rem,5vw,4rem);font-weight:800\">THREE WAYS TO<br><span style=\"color:#3B82F6\">GET RESULTS</span></h2>\n<!-- /wp:heading -->\n\n<!-- wp:columns {\"className\":\"is-layout-flex wp-block-columns-is-layout-flex ep-services-cols\"} -->\n<div class=\"wp-block-columns is-layout-flex wp-block-columns-is-layout-flex ep-services-cols\"><!-- wp:column {\"className\":\"is-layout-flow wp-block-column-is-layout-flow\"} -->\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\"><!-- wp:group {\"cla