p-block-cover__inner-container\"><!-- wp:columns {\"className\":\"is-layout-flex wp-block-columns-is-layout-flex ep-why-cols\"} -->\n<div class=\"wp-block-columns is-layout-flex wp-block-columns-is-layout-flex ep-why-cols\"><!-- wp:column {\"width\":\"60%\",\"className\":\"is-layout-flow wp-block-column-is-layout-flow\"} -->\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:60%\"><!-- wp:heading {\"level\":6,\"className\":\"ep-eyebrow\",\"style\":{\"color\":{\"text\":\"#3B82F6\"},\"typography\":{\"fontSize\":\"0.75rem\",\"fontWeight\":\"700\",\"letterSpacing\":\"0.12em\",\"textTransform\":\"uppercase\"}}} -->\n<h6 class=\"wp-block-heading ep-eyebrow has-text-color\" style=\"color:#3B82F6;font-size:0.75rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase\">Why EP Fitness</h6>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"style\":{\"color\":{\"text\":\"#FFFFFF\"},\"typography\":{\"fontSize\":\"clamp(2rem,4vw,3rem)\",\"fontWeight\":\"800\"}}} -->\n<h2 class=\"wp-block-heading has-text-color\" style=\"color:#FFFFFF;font-size:clamp(2rem,4vw,3rem);font-weight:800\">YOU\'LL <span style=\"color:#60A5FA\">ALWAYS HAVE A COACH.</span></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.8)\"},\"typography\":{\"fontSize\":\"1rem\"}}} -->\n<p class=\"has-text-color\" style=\"color:rgba(255,255,255,0.8);font-size:1rem\">No guesswork. No generic plans. Every EP Fitness member gets a 100% customized program built around their goals, schedule, and fitness level — with a real coach checking in every step of the way.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"width\":\"40%\",\"className\":\"is-layout-flow wp-block-column-is-layout-flow\"} -->\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:40%\"><!-- wp:list {\"className\":\"ep-checklist\"} -->\n<ul class=\"wp-block-list ep-checklist\"><!-- wp:list-item -->\n<li>Comprehensive body assessment</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>100% custom programming</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Weekly coach check-ins</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Nutrition guidance included</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Progress tracked every session</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Same coach, every session</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>No long-term contracts required</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Free body comp assessment on Day 1</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div></div>\n<!-- /wp:cover -->\n\n<!-- wp:group {\"className\":\"is-layout-constrained wp-block-group-is-layout-constrained ep-testimonials-dark\",\"style\":{\"color\":{\"background\":\"#0F172A\"},\"spacing\":{\"padding\":{\"top\":\"clamp(5rem, 10vw, 8rem)\",\"bottom\":\"clamp(5rem, 10vw, 8rem)\",\"left\":\"2rem\",\"right\":\"2rem\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group is-layout-constrained wp-block-group-is-layout-constrained ep-testimonials-dark has-background\" style=\"background-color:#0F172A;padding-top:clamp(5rem, 10vw, 8rem);padding-right:2rem;padding-bottom:clamp(5rem, 10vw, 8rem);padding-left:2rem\"><!-- wp:heading {\"level\":6,\"className\":\"ep-eyebrow\",\"style\":{\"color\":{\"text\":\"#60A5FA\"},\"typography\":{\"fontSize\":\"0.75rem\",\"fontWeight\":\"700\",\"letterSpacing\":\"0.12em\",\"textTransform\":\"uppercase\"}}} -->\n<h6 class=\"wp-block-heading ep-eyebrow has-text-color\" style=\"color:#60A5FA;font-size:0.75rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase\">Real Results</h6>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"style\":{\"color\":{\"text\":\"#FFFFFF\"},\"typography\":{\"fontSize\":\"clamp(2.2rem,4vw,3.2rem)\",\"fontWeight\":\"800\"}}} -->\n<h2 class=\"wp-block-heading has-text-color\" style=\"color:#FFFFFF;font-size:clamp(2.2rem,4vw,3.2rem);font-weight:800\">Clients Who Showed Up.<br><span style=\"color:#60A5FA\">Results That Speak.</span></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.65)\"},\"typography\":{\"fontSize\":\"1rem\"}}} -->\n<p class=\"has-text-color\" style=\"color:rgba(255,255,255,0.65);font-size:1rem\">These aren\'t before-and-after photos. These are people who decided to stop starting over — and finally finished what they started.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:columns {\"className\":\"is-layout-flex wp-block-columns-is-layout-flex ep-testimonials-cols\"} -->\n<div class=\"wp-block-columns is-layout-flex wp-block-columns-is-layout-flex ep-testimonials-cols\"><!-- wp:column {\"className\":\"is-layout-flow wp-block-column-is-layout-flow\"} -->\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\"><!-- wp:group {\"className\":\"ep-testimonial-card is-layout-constrained wp-block-group-is-layout-constrained\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group ep-testimonial-card is-layout-constrained wp-block-group-is-layout-constrained\"><!-- wp:paragraph {\"className\":\"ep-testimonial-quote\"} -->\n<p class=\"ep-testimonial-quote\">“I\'ve tried every gym in Wichita. EP is the first place I showed up every single week for a year. I lost 34 lbs and kept it off.”</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:group {\"className\":\"ep-testimonial-attribution is-layout-flex wp-block-group-is-layout-flex\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\",\"verticalAlignment\":\"center\"}} -->\n<div class=\"wp-block-group ep-testimonial-attribution is-layout-flex wp-block-group-is-layout-flex\"><!-- wp:group {\"className\":\"ep-testimonial-avatar is-layout-constrained wp-block-group-is-layout-constrained\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group ep-t